import re

from erk_slack_bot.models import (
    Command,
    OneShotCommand,
    OneShotMissingMessageCommand,
    PlanListCommand,
    QuoteCommand,
)


def strip_mentions(text: str) -> str:
    return re.sub(r"<@[^>]+>", " ", text).strip()


def parse_erk_command(text: str) -> Command | None:
    message = strip_mentions(text)
    if not message:
        return None

    normalized = " ".join(message.split())
    lowered = normalized.lower()

    if lowered == "plan list":
        return PlanListCommand()
    if lowered == "quote":
        return QuoteCommand()

    one_shot_match = re.match(r"(?i)^one[- ]shot\b", normalized)
    if not one_shot_match:
        return None

    one_shot_message = normalized[one_shot_match.end() :].strip()
    if not one_shot_message:
        return OneShotMissingMessageCommand()
    return OneShotCommand(message=one_shot_message)

import asyncio
from collections.abc import Awaitable, Callable
from shutil import which

from click.testing import CliRunner

from erk import cli
from erk_slack_bot.models import RunResult


async def run_erk_plan_list() -> RunResult:
    result = await asyncio.to_thread(CliRunner().invoke, cli, ["plan", "list"])
    output = (result.output or "").strip() or "(no output)"
    return RunResult(exit_code=result.exit_code, output=output)


async def run_erk_one_shot(message: str, *, timeout_seconds: float) -> RunResult:
    if which("uv") is None:
        return RunResult(exit_code=127, output="Failed to start process: uv was not found in PATH")

    try:
        process = await asyncio.create_subprocess_exec(
            "uv",
            "run",
            "erk",
            "one-shot",
            message,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        stdout_bytes, stderr_bytes = await asyncio.wait_for(
            process.communicate(), timeout=timeout_seconds
        )
    except TimeoutError:
        process.terminate()
        try:
            await asyncio.wait_for(process.wait(), timeout=2)
        except TimeoutError:
            process.kill()
            await process.wait()
        output = "(no output)"
        return RunResult(exit_code=124, output=output, timed_out=True)

    stdout = (stdout_bytes or b"").decode()
    stderr = (stderr_bytes or b"").decode()
    output = "\n".join(part for part in [stdout, stderr] if part).strip() or "(no output)"
    return RunResult(exit_code=process.returncode or 0, output=output)


async def stream_erk_one_shot(
    message: str,
    *,
    timeout_seconds: float,
    on_line: Callable[[str], Awaitable[None]] | None,
) -> RunResult:
    if which("uv") is None:
        return RunResult(exit_code=127, output="Failed to start process: uv was not found in PATH")

    process = await asyncio.create_subprocess_exec(
        "uv",
        "run",
        "erk",
        "one-shot",
        message,
        stdout=asyncio.subprocess.PIPE,
        stderr=asyncio.subprocess.STDOUT,
    )

    lines: list[str] = []

    async def _read_lines() -> None:
        if process.stdout is None:
            return
        while True:
            raw_line = await process.stdout.readline()
            if not raw_line:
                break
            line = raw_line.decode().rstrip("\n")
            lines.append(line)
            if on_line is not None:
                await on_line(line)

    try:
        await asyncio.wait_for(_read_lines(), timeout=timeout_seconds)
    except TimeoutError:
        process.terminate()
        try:
            await asyncio.wait_for(process.wait(), timeout=2)
        except TimeoutError:
            process.kill()
            await process.wait()
        output = "\n".join(lines).strip() or "(no output)"
        return RunResult(exit_code=124, output=output, timed_out=True)

    await process.wait()
    output = "\n".join(lines).strip() or "(no output)"
    return RunResult(exit_code=process.returncode or 0, output=output)

import re
from importlib import resources
from importlib.util import find_spec
from pathlib import Path

from erk_slack_bot.config import Settings

_QUOTE_RESOURCE_PACKAGE = "erk_slack_bot.resources"
_QUOTE_RESOURCE_NAME = "QUOTE.md"
_PR_URL_RE = re.compile(r"^PR:\s+(https://\S+)")
_RUN_URL_RE = re.compile(r"^Run:\s+(https://\S+)")


def extract_slack_message_ts(message_result: object) -> str | None:
    if message_result is None:
        return None
    if isinstance(message_result, dict):
        ts = message_result.get("ts")
        return str(ts) if ts else None

    get_method = getattr(message_result, "get", None)
    if callable(get_method):
        ts = get_method("ts")
        if ts:
            return str(ts)

    data = getattr(message_result, "data", None)
    if isinstance(data, dict):
        ts = data.get("ts")
        return str(ts) if ts else None
    return None


def extract_one_shot_links(output: str) -> tuple[str | None, str | None]:
    pr_url: str | None = None
    run_url: str | None = None
    for line in output.splitlines():
        if pr_url is None:
            pr_match = _PR_URL_RE.match(line.strip())
            if pr_match:
                pr_url = pr_match.group(1)
        if run_url is None:
            run_match = _RUN_URL_RE.match(line.strip())
            if run_match:
                run_url = run_match.group(1)
        if pr_url and run_url:
            break
    return pr_url, run_url


def tail_output_lines(output: str, *, max_lines: int) -> str:
    lines = [line for line in output.splitlines() if line.strip()]
    if len(lines) <= max_lines:
        return "\n".join(lines)
    return "\n".join(lines[-max_lines:])


def chunk_for_slack(text: str, *, max_chars: int) -> list[str]:
    if len(text) <= max_chars:
        return [text]

    chunks: list[str] = []
    current = ""
    for line in text.splitlines():
        candidate = f"{current}\n{line}" if current else line
        if len(candidate) <= max_chars:
            current = candidate
            continue
        if current:
            chunks.append(current)
            current = line
            continue
        remainder = line
        while len(remainder) > max_chars:
            chunks.append(remainder[:max_chars])
            remainder = remainder[max_chars:]
        current = remainder
    if current:
        chunks.append(current)
    return chunks


def build_one_shot_progress_text(*, lines: list[str], running: bool, settings: Settings) -> str:
    state = "⏳ Running `erk one-shot`" if running else "✅ Finished `erk one-shot`."
    if not lines:
        return state
    tail = "\n".join(lines[-settings.one_shot_progress_tail_lines :])
    return f"{state}\n\n```{tail}```"


def load_quote_text() -> str:
    if find_spec(_QUOTE_RESOURCE_PACKAGE) is not None:
        resource_root = resources.files(_QUOTE_RESOURCE_PACKAGE)
        resource_quote_file = resource_root.joinpath(_QUOTE_RESOURCE_NAME)
        if resource_quote_file.is_file():
            quote = resource_quote_file.read_text(encoding="utf-8").strip()
            return quote or "QUOTE.md is empty."

    fallback_quote_file = Path(__file__).parent.joinpath("resources", _QUOTE_RESOURCE_NAME)
    if not fallback_quote_file.is_file():
        return f"{_QUOTE_RESOURCE_NAME} resource was not found."

    quote = fallback_quote_file.read_text(encoding="utf-8").strip()
    return quote or "QUOTE.md is empty."

import unittest

from erk_slack_bot.models import (
    OneShotCommand,
    OneShotMissingMessageCommand,
    PlanListCommand,
    QuoteCommand,
)
from erk_slack_bot.parser import parse_erk_command


class TestParseErkCommand(unittest.TestCase):
    def test_parse_plan_list(self) -> None:
        command = parse_erk_command("<@U123> plan list")
        self.assertIsInstance(command, PlanListCommand)

    def test_parse_quote(self) -> None:
        command = parse_erk_command("<@U123> quote")
        self.assertIsInstance(command, QuoteCommand)

    def test_parse_one_shot_message(self) -> None:
        command = parse_erk_command("<@U123> one-shot Review README")
        self.assertIsInstance(command, OneShotCommand)
        assert isinstance(command, OneShotCommand)
        self.assertEqual(command.message, "Review README")

    def test_parse_one_shot_missing_message(self) -> None:
        command = parse_erk_command("<@U123> one-shot")
        self.assertIsInstance(command, OneShotMissingMessageCommand)

    def test_parse_unknown(self) -> None:
        self.assertIsNone(parse_erk_command("<@U123> unsupported"))


if __name__ == "__main__":
    unittest.main()

